// ==============================================================
// WF3 - Validar e preparar (monday)
// Aceita JSON normal ou multipart/form-data com campo payload.
// Calcula ocorrencias, atestados e ledger anti-duplicidade.
// ==============================================================

const COL_UUID = 'text_mm2xjend';
const COL_PROTOCOLO = 'text_mm2xsvg6';
const COL_DATA_INICIO = 'date_mm2xtp93';
const COL_DATA_FIM = 'date_mm2xrr5q';
const COL_EXPIRA_EM = 'date_mm2xrvt4';
const COL_CONCLUIDO_EM = 'date_mm2xh1vm';
const COL_EDITADO_EM = 'date_mm2x62fq';
const COL_STATUS = 'color_mm2xkqpc';
const COL_EDITADO = 'boolean_mm2x1aa4';
const COL_QTD_FALTAS = 'numeric_mm2xe2zk';
const COL_QTD_ATRASOS = 'numeric_mm2x18hh';
const COL_TOTAL_MIN = 'numeric_mm2x4fjj';
const COL_DIAS_EXTRAS = 'long_text_mm2x73w6';
const COL_DIAS_DESATIV = 'long_text_mm2xm820';
const COL_RESPOSTAS = 'long_text_mm2xtcpw';
const COL_TOTAL_MIN_DEVIDOS = 'numeric_mm3455ss';
const COL_DIAS_PERDE_VT = 'numeric_mm345xb6';
const COL_DIAS_PERDE_VR = 'numeric_mm34a3ph';
const COL_CONTRATO = 'text_mm2x1ktb';
const COL_CHAPA = 'text_mm33v9kp';
const COL_OPTANTE_VT = 'color_mm34ry47';
const COL_TRABALHA_SAB = 'color_mm34yyet';
const COL_ITEM_ORIGEM = 'link_mm2x1rk0';
const COL_QTD_SABADOS_EX = 'numeric_mm3bvgy';
const COL_SABADOS_EX_TXT = 'text_mm3bfn6h';
const COL_ATESTADOS_JSON = 'long_text_mm3cp43g';
const COL_BENEF_LEDGER = 'long_text_mm3ct3hg';
const COL_QTD_ATESTADOS = 'numeric_mm3c4cse';
const COL_ARQUIVOS_ATESTADO = 'file_mm3cvt54';
const COL_STATUS_CANCELAMENTO = 'color_mm3b9v4n';

const webhook = $('Webhook1').first().json;
let body = webhook.body || {};
if (typeof body.payload === 'string') {
  try { body = JSON.parse(body.payload); }
  catch (e) { return [{ json: { _statusCode: 400, _erro: 'payload_invalido', mensagem: 'Campo payload nao contem JSON valido.' } }]; }
} else if (body.payload && typeof body.payload === 'object') {
  body = body.payload;
}

const uuid = webhook.query?.uuid || body.uuid;
const respostas = Array.isArray(body.respostas) ? body.respostas : [];
const protocolo = body.protocolo || null;
const diasExtras = Array.isArray(body.dias_extras) ? body.dias_extras : [];
const diasDesativ = Array.isArray(body.dias_desativados) ? body.dias_desativados : [];
const sabadosExtras = Array.isArray(body.sabados_extras)
  ? body.sabados_extras.filter(d => typeof d === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(d))
  : [];
const atestadosPayload = Array.isArray(body.atestados) ? body.atestados : [];
const ehCorrecaoFlag = !!body.eh_correcao;

const all = $input.all();
function firstRealItem() {
  for (const it of all) {
    const j = it.json;
    if (j && j.id && (j.column_values || j.name)) return j;
  }
  return null;
}
const item = firstRealItem();
if (!item) return [{ json: { _statusCode: 404, _erro: 'nao_encontrado', mensagem: 'Processamento nao encontrado.' } }];

const columnValues = item.column_values ?? [];
const getCol = (id) => columnValues.find(c => c.id === id);
const text = (id) => getCol(id)?.text ?? null;
const rawValue = (id) => getCol(id)?.value ?? null;

function parseCheckbox(id) {
  const v = rawValue(id);
  if (!v) return false;
  try {
    const parsed = typeof v === 'string' ? JSON.parse(v) : v;
    return parsed?.checked === true || parsed?.checked === 'true';
  } catch { return false; }
}
function parseLongTextJson(id, fallback) {
  const t = text(id);
  if (!t) return fallback;
  try { return JSON.parse(t); } catch { return fallback; }
}
function bool(v) {
  return v === true || v === 'true' || v === 'SIM' || v === 'sim' || v === 1;
}
function normAtestado(a, index) {
  const id = String(a.id || `atest-${index + 1}`).trim();
  const dataInicio = a.data_inicio || a.dataInicio;
  const dataFim = a.data_fim || a.dataFim;
  return {
    id,
    data_inicio: dataInicio,
    data_fim: dataFim,
    primeiro_dia_foi_trabalhar: bool(a.primeiro_dia_foi_trabalhar ?? a.primeiroDiaFoiTrabalhar),
    primeiro_dia_trabalhou_seis_horas: a.primeiro_dia_trabalhou_seis_horas ?? a.primeiroDiaTrabalhouSeisHoras ?? null,
    nome_arquivo: a.nome_arquivo || a.nomeArquivo || 'Atestado',
    tamanho_arquivo: Number(a.tamanho_arquivo ?? a.tamanhoArquivo ?? 0) || 0,
    monday_item_id: a.monday_item_id || a.mondayItemId || null,
    monday_item_url: a.monday_item_url || a.mondayItemUrl || a.arquivo_url || a.arquivoUrl || null
  };
}
function dateValue(d, withTime) {
  if (!d) return null;
  const x = d instanceof Date ? d : new Date(d);
  if (Number.isNaN(x.getTime())) return null;
  const yyyy = x.getUTCFullYear();
  const mm = String(x.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(x.getUTCDate()).padStart(2, '0');
  if (!withTime) return { date: `${yyyy}-${mm}-${dd}` };
  const hh = String(x.getUTCHours()).padStart(2, '0');
  const mi = String(x.getUTCMinutes()).padStart(2, '0');
  const ss = String(x.getUTCSeconds()).padStart(2, '0');
  return { date: `${yyyy}-${mm}-${dd}`, time: `${hh}:${mi}:${ss}` };
}
function dow(d) { return new Date(d + 'T00:00:00Z').getUTCDay(); }
function isSabado(d) { return dow(d) === 6; }
function isDomingo(d) { return dow(d) === 0; }
function isDiaUtil(d) { const x = dow(d); return x >= 1 && x <= 5; }
function jornadaMin(d) { if (isDomingo(d)) return 0; if (isSabado(d)) return 240; return 480; }
function rangeDatas(inicio, fim) {
  const out = [];
  const cur = new Date(inicio + 'T00:00:00Z');
  const end = new Date(fim + 'T00:00:00Z');
  while (cur <= end) {
    out.push(cur.toISOString().slice(0, 10));
    cur.setUTCDate(cur.getUTCDate() + 1);
  }
  return out;
}

const statusLabel = text(COL_STATUS);
const dataInicio = text(COL_DATA_INICIO);
const dataFim = text(COL_DATA_FIM);
const expiraEm = text(COL_EXPIRA_EM);
const concluidoEmAtual = text(COL_CONCLUIDO_EM);
const jaEstavaEditado = parseCheckbox(COL_EDITADO);
const agora = new Date();

if (statusLabel === 'Expirado' || (expiraEm && agora > new Date(expiraEm + 'T23:59:59Z') && statusLabel !== 'Concluído')) {
  return [{ json: { _statusCode: 410, _erro: 'expirado', mensagem: 'Link expirado.' } }];
}
const statusCancelamento = text(COL_STATUS_CANCELAMENTO);
if (statusCancelamento === 'Cancelada' || statusCancelamento === 'Cancelada parcialmente') {
  return [{ json: { _statusCode: 409, _erro: 'convocacao_cancelada', mensagem: 'Esta convocacao foi cancelada e nao pode ser finalizada nem corrigida.', status_cancelamento: statusCancelamento } }];
}
if ((statusLabel === 'Concluído' || statusLabel === 'Concluido') && !ehCorrecaoFlag) {
  return [{ json: { _statusCode: 409, _erro: 'ja_concluido', mensagem: 'Este formulario ja foi finalizado.' } }];
}
if (!protocolo || !/^PROT-[A-Z0-9-]+$/i.test(protocolo)) {
  return [{ json: { _statusCode: 400, _erro: 'protocolo_invalido', mensagem: 'Protocolo ausente ou invalido.' } }];
}

const sabadosExtrasAnterioresTxt = text(COL_SABADOS_EX_TXT) || '';
const sabadosExtrasAnteriores = sabadosExtrasAnterioresTxt.split(/[,;\n]/).map(s => s.trim()).filter(s => /^\d{4}-\d{2}-\d{2}$/.test(s));
const setAnteriores = new Set(sabadosExtrasAnteriores);
const setAtuais = new Set(sabadosExtras);
const sabadosRemovidos = sabadosExtrasAnteriores.filter(d => !setAtuais.has(d));
if (sabadosRemovidos.length > 0) {
  return [{ json: { _statusCode: 409, _erro: 'sabados_pagos_removidos', mensagem: `Sabados extras ja pagos nao podem ser removidos: ${sabadosRemovidos.join(', ')}.`, sabados_removidos: sabadosRemovidos } }];
}
const sabadosExtrasNovos = sabadosExtras.filter(d => !setAnteriores.has(d));
const sabadosExtrasFinal = [...new Set([...sabadosExtrasAnteriores, ...sabadosExtras])].sort();
const sabadosExtrasSet = new Set(sabadosExtrasFinal);

const trabalhaSabado = String(text(COL_TRABALHA_SAB) || '').toUpperCase() === 'SIM';
function diaConta(d) {
  if (isDomingo(d)) return false;
  if (isSabado(d)) return trabalhaSabado || sabadosExtrasSet.has(d);
  return true;
}

const diasBase = [];
if (dataInicio && dataFim) {
  for (const d of rangeDatas(dataInicio, dataFim)) {
    if (!isDomingo(d) && (!isSabado(d) || trabalhaSabado)) diasBase.push(d);
  }
}
const desativ = new Set(diasDesativ);
const diasValidos = [...new Set([...diasBase, ...diasExtras, ...sabadosExtrasFinal])].filter(d => !desativ.has(d)).sort();

const atestados = atestadosPayload.map(normAtestado);
for (const a of atestados) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(String(a.data_inicio || '')) || !/^\d{4}-\d{2}-\d{2}$/.test(String(a.data_fim || ''))) {
    return [{ json: { _statusCode: 400, _erro: 'atestado_data_invalida', mensagem: `Atestado ${a.id} sem datas validas.` } }];
  }
  if (a.data_inicio > a.data_fim || a.data_inicio < dataInicio || a.data_fim > dataFim) {
    return [{ json: { _statusCode: 400, _erro: 'atestado_fora_periodo', mensagem: `Atestado ${a.id} fora do periodo da convocacao.` } }];
  }
}

const mapaRespostas = new Map(respostas.map(r => [r.data, r]));
const respostasFinal = [];
for (const dia of diasValidos) {
  const r = mapaRespostas.get(dia);
  if (!r || !r.tipo) return [{ json: { _statusCode: 400, _erro: 'resposta_faltando', mensagem: `Resposta faltando para o dia ${dia}.` } }];
  if (!['sem_ocorrencia','falta','atraso'].includes(r.tipo)) return [{ json: { _statusCode: 400, _erro: 'tipo_invalido', mensagem: `Tipo invalido em ${dia}: ${r.tipo}` } }];
  const minutos = r.minutos_atraso;
  if (r.tipo === 'atraso' && (!Number.isInteger(minutos) || minutos <= 0)) return [{ json: { _statusCode: 400, _erro: 'minutos_invalidos', mensagem: `Minutos de atraso invalidos em ${dia}.` } }];
  respostasFinal.push({ data: dia, tipo: r.tipo, minutos_atraso: r.tipo === 'atraso' ? minutos : null });
}

const descontosPorDiaMap = new Map();
function entry(d) {
  if (!descontosPorDiaMap.has(d)) descontosPorDiaMap.set(d, { data: d, vr: false, vt: false, vr_tipo: null, minutos_atraso: 0, origens: [] });
  return descontosPorDiaMap.get(d);
}
function addDesconto(d, opts) {
  if (!diaConta(d)) return;
  const e = entry(d);
  if (opts.vt) e.vt = true;
  if (opts.vr) {
    e.vr = true;
    if (opts.vr_tipo === 'integral' || e.vr_tipo !== 'integral') e.vr_tipo = opts.vr_tipo || 'integral';
    if (opts.minutos_atraso) e.minutos_atraso = Math.max(e.minutos_atraso || 0, opts.minutos_atraso);
  }
  if (opts.origem && !e.origens.includes(opts.origem)) e.origens.push(opts.origem);
}

for (const d of diasDesativ) {
  if (!diaConta(d)) continue;
  addDesconto(d, { vt: true, vr: !isSabado(d), vr_tipo: 'integral', origem: 'desconsiderado' });
}
for (const r of respostasFinal) {
  if (!diaConta(r.data)) continue;
  if (r.tipo === 'falta') addDesconto(r.data, { vt: true, vr: !isSabado(r.data), vr_tipo: 'integral', origem: 'falta' });
  if (r.tipo === 'atraso' && !isSabado(r.data)) addDesconto(r.data, { vr: true, vt: false, vr_tipo: 'atraso', minutos_atraso: r.minutos_atraso || 0, origem: 'atraso' });
}
for (const a of atestados) {
  const diasAtestado = rangeDatas(a.data_inicio, a.data_fim);
  for (const d of diasAtestado) {
    if (!diaConta(d)) continue;
    const primeiro = d === a.data_inicio;
    if (primeiro) {
      if (isDiaUtil(d)) {
        if (!a.primeiro_dia_foi_trabalhar) addDesconto(d, { vt: true, vr: true, vr_tipo: 'integral', origem: `atestado:${a.id}` });
        else if (a.primeiro_dia_trabalhou_seis_horas === false) addDesconto(d, { vt: false, vr: true, vr_tipo: 'integral', origem: `atestado:${a.id}` });
      } else if (isSabado(d) && !a.primeiro_dia_foi_trabalhar) {
        addDesconto(d, { vt: true, vr: false, origem: `atestado:${a.id}` });
      }
    } else {
      addDesconto(d, { vt: true, vr: !isSabado(d), vr_tipo: 'integral', origem: `atestado:${a.id}` });
    }
  }
}

const descontosPorDia = [...descontosPorDiaMap.values()].sort((a, b) => a.data.localeCompare(b.data));
const qtdFaltas = respostasFinal.filter(r => r.tipo === 'falta').length;
const qtdAtrasos = respostasFinal.filter(r => r.tipo === 'atraso').length;
const totalMin = respostasFinal.reduce((acc, r) => acc + (r.tipo === 'atraso' ? (r.minutos_atraso || 0) : 0), 0);
const diasPerdeVT = descontosPorDia.filter(d => d.vt).length;
const diasPerdeVR = descontosPorDia.filter(d => d.vr && d.vr_tipo === 'integral').length;
let totalMinDevidos = 0;
for (const d of descontosPorDia) {
  if (d.vt || d.origens.includes('falta') || d.origens.includes('desconsiderado')) totalMinDevidos += jornadaMin(d.data);
  else if (d.vr_tipo === 'atraso') totalMinDevidos += d.minutos_atraso || 0;
}

const ledger = {};
for (const d of descontosPorDia) {
  let vrPct = 0;
  if (d.vr) {
    if (d.vr_tipo === 'atraso' && d.minutos_atraso) {
      const jor = jornadaMin(d.data) || 480;
      vrPct = Math.min(100, Math.round((d.minutos_atraso / jor) * 10000) / 100);
    } else {
      vrPct = 100;
    }
  }
  const vtPct = d.vt ? 100 : 0;
  ledger[d.data] = { vr: !!d.vr, vt: !!d.vt, vr_percentual: vrPct, vt_percentual: vtPct, origens: d.origens };
  if (d.vr_tipo) ledger[d.data].vr_tipo = d.vr_tipo;
  if (d.minutos_atraso) ledger[d.data].minutos_atraso = d.minutos_atraso;
}

const ehReedicao = (statusLabel === 'Concluído' || statusLabel === 'Concluido') || ehCorrecaoFlag;
const editadoFlag = ehReedicao || jaEstavaEditado;
const concluidoEmFinal = concluidoEmAtual || `${agora.toISOString().slice(0, 19).replace('T', ' ')}`;

const columnValuesUpdate = {
  [COL_STATUS]: { label: 'Concluído' },
  [COL_PROTOCOLO]: protocolo,
  [COL_CONCLUIDO_EM]: dateValue(concluidoEmAtual ? concluidoEmAtual : agora.toISOString(), true),
  [COL_EDITADO]: { checked: editadoFlag ? 'true' : 'false' },
  [COL_EDITADO_EM]: ehReedicao ? dateValue(agora.toISOString(), true) : null,
  [COL_QTD_FALTAS]: String(qtdFaltas),
  [COL_QTD_ATRASOS]: String(qtdAtrasos),
  [COL_TOTAL_MIN]: String(totalMin),
  [COL_TOTAL_MIN_DEVIDOS]: String(totalMinDevidos),
  [COL_DIAS_PERDE_VT]: String(diasPerdeVT),
  [COL_DIAS_PERDE_VR]: String(diasPerdeVR),
  [COL_DIAS_EXTRAS]: { text: JSON.stringify(diasExtras) },
  [COL_DIAS_DESATIV]: { text: JSON.stringify(diasDesativ) },
  [COL_RESPOSTAS]: { text: JSON.stringify(respostasFinal) },
  [COL_QTD_SABADOS_EX]: String(sabadosExtrasFinal.length),
  [COL_SABADOS_EX_TXT]: sabadosExtrasFinal.length ? sabadosExtrasFinal.join(', ') : '',
  [COL_ATESTADOS_JSON]: { text: JSON.stringify(atestados) },
  [COL_BENEF_LEDGER]: { text: JSON.stringify(ledger) },
  [COL_QTD_ATESTADOS]: String(atestados.length)
};
for (const k of Object.keys(columnValuesUpdate)) if (columnValuesUpdate[k] === null || columnValuesUpdate[k] === undefined) delete columnValuesUpdate[k];

const binary = $('Webhook1').first().binary || {};
const atestadosParaUpload = atestados
  .filter(a => !!binary[`atestado_${a.id}`])
  .map(a => ({ ...a, binary_name: `atestado_${a.id}`, historico_file_column: COL_ARQUIVOS_ATESTADO }));

return [{
  json: {
    _statusCode: 200,
    item_id: String(item.id),
    uuid,
    protocolo,
    editado: editadoFlag,
    eh_reedicao: ehReedicao,
    concluido_em_final: concluidoEmFinal,
    column_values_json: JSON.stringify(columnValuesUpdate),
    nome: item.name,
    chapa: text(COL_CHAPA) || '',
    contrato: text(COL_CONTRATO) || '',
    data_inicio: dataInicio,
    data_fim: dataFim,
    optante_vt: text(COL_OPTANTE_VT) || 'NAO',
    trabalha_sabado: text(COL_TRABALHA_SAB) || 'NAO',
    item_origem_id: (function() {
      const linkText = text(COL_ITEM_ORIGEM) || '';
      const linkRaw = rawValue(COL_ITEM_ORIGEM);
      let url = linkText;
      if (!url && linkRaw) {
        try { const parsed = typeof linkRaw === 'string' ? JSON.parse(linkRaw) : linkRaw; url = parsed?.url || ''; } catch { url = ''; }
      }
      const m = String(url).match(/pulses\/(\d+)/);
      return m ? m[1] : null;
    })(),
    qtd_faltas: qtdFaltas,
    qtd_atrasos: qtdAtrasos,
    total_min_atraso: totalMin,
    total_min_devidos: totalMinDevidos,
    dias_perde_vt: diasPerdeVT,
    dias_perde_vr: diasPerdeVR,
    respostas_final: respostasFinal,
    descontos_por_dia: descontosPorDia,
    beneficios_descontados: ledger,
    atestados,
    atestados_para_upload: atestadosParaUpload,
    dias_desativ: diasDesativ,
    sabados_extras: sabadosExtrasFinal,
    sabados_extras_anteriores: sabadosExtrasAnteriores,
    sabados_extras_novos: sabadosExtrasNovos,
    qtd_sabados_extras: sabadosExtrasFinal.length,
    qtd_sabados_extras_novos: sabadosExtrasNovos.length,
    audit_sabados: { timestamp: agora.toISOString(), uuid, protocolo, acao: sabadosExtrasNovos.length > 0 ? 'adicionou' : 'idempotente', sabados_anteriores: sabadosExtrasAnteriores, sabados_payload: sabadosExtras, sabados_novos: sabadosExtrasNovos, sabados_final: sabadosExtrasFinal, total_apos: sabadosExtrasFinal.length }
  }
}];

const hist = $('Validar e preparar1').first().json;

const COL_STATUS = 'color_mm0r8mjr';
const COL_DATA_INICIO = 'date_mm0r6tyr';
const COL_DATA_FIM = 'date_mm0rzpyv';
const COL_RESIDUAL_VR = 'numeric_mm0r1691';
const COL_RESIDUAL_VT = 'numeric_mm0rtwwg';
const COL_DESCONTADO_VR = 'numeric_mm0rqy6z';
const COL_DESCONTADO_VT = 'numeric_mm0r6cn0';

function norm(v) {
  return String(v || '').toUpperCase().trim();
}

function num(v) {
  return Number(String(v || '0').replace(',', '.')) || 0;
}

const descontos = [];

for (const item of $input.all()) {
  const j = item.json;
  if (!j || !j.id || !j.column_values) continue;

  const cols = {};
  for (const c of j.column_values) {
    cols[c.id] = {
      text: c.text,
      value: c.value
    };
  }

  const dataInicio = cols[COL_DATA_INICIO]?.text || null;
  const dataFim = cols[COL_DATA_FIM]?.text || null;

  if (dataInicio !== hist.data_inicio || dataFim !== hist.data_fim) {
    descontos.push(j);
    continue;
  }

  const status = norm(cols[COL_STATUS]?.text);
  const descontadoVR = num(cols[COL_DESCONTADO_VR]?.text);
  const descontadoVT = num(cols[COL_DESCONTADO_VT]?.text);

  const jaConsumido =
    status === 'PARCIAL' ||
    status === 'FINALIZADO' ||
    descontadoVR > 0 ||
    descontadoVT > 0;

  if (jaConsumido) {
    return [{
      json: {
        _statusCode: 409,
        _erro: 'desconto_em_consumo',
        mensagem: 'NÃ£o Ã© possÃ­vel corrigir: o desconto desta convocaÃ§Ã£o jÃ¡ foi parcial ou totalmente consumido.',
        item_id_desconto: String(j.id),
        status,
        descontadoVR,
        descontadoVT
      }
    }];
  }

  descontos.push(j);
}

return [{
  json: {
    _statusCode: 200,
    ok: true,
    descontos_existentes: descontos
  }
}];

// ==============================================================
// WF3 - Decidir Desconto
// Usa descontos_por_dia calculado pelo Validar e preparar, incluindo
// faltas, desconsideracoes, atrasos e atestados sem duplicar datas.
// ==============================================================

const BOARD_DESCONTOS = 18400981023;
const GROUP_DESCONTOS = 'group_mm0rmjs3';

const COL_D_NOME = 'dropdown_mm0rgfrx';
const COL_D_MATRICULA = 'text_mm0rpqxs';
const COL_D_CPF = 'text_mm0r5ted';
const COL_D_DATA_INICIO = 'date_mm0r6tyr';
const COL_D_DATA_FIM = 'date_mm0rzpyv';
const COL_D_DIAS_PERDE_VT = 'numeric_mm3428yj';
const COL_D_DIAS_PERDE_VR = 'numeric_mm34p6p7';
const COL_D_QTD_ATRASOS = 'numeric_mm2pj1av';
const COL_D_DESCONTO_VR = 'numeric_mm0rgsaw';
const COL_D_DESCONTO_VT = 'numeric_mm0r5tca';
const COL_D_STATUS = 'color_mm0r8mjr';
const COL_D_RESIDUAL_VR = 'numeric_mm0r1691';
const COL_D_RESIDUAL_VT = 'numeric_mm0rtwwg';
const COL_D_DESCONTADO_VR = 'numeric_mm0rqy6z';
const COL_D_DESCONTADO_VT = 'numeric_mm0r6cn0';

const hist = $('Validar e preparar1').first().json;
const origemRaw = $('Get Item Origem1').first().json;
const origemItem = origemRaw?.data?.item ?? origemRaw?.item ?? origemRaw;
const origemColumns = origemItem?.column_values ?? [];
const origemGet = (id) => origemColumns.find(c => c.id === id)?.text ?? null;
const nomeNorm = (s) => String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase().trim();
const round2 = (n) => Math.round(Number(n || 0) * 100) / 100;
const num = (v) => Number(String(v || '0').replace(',', '.')) || 0;

const chapa = String(hist.chapa || '').trim();
const cpf = String(origemGet('dup__of_matr_cula') || '').trim();
const funcao = nomeNorm(origemGet('texto0'));
const contrato = nomeNorm(hist.contrato);
const optanteVtRaw = nomeNorm(origemGet('optante___vt'));
const optanteVT = optanteVtRaw === 'SIM' || optanteVtRaw === 'SIM*';
const vtSoVolta = optanteVtRaw === 'SIM*';

let vrDia = 0;
let vtDia = 0;
let regraAplicada = '';
if (contrato === 'DETRAN') {
  if (funcao.includes('PORTARIA')) { vrDia = 514.50 / 30; regraAplicada = 'DETRAN - Agente de Portaria'; }
  else if (funcao.includes('MOTO BOY')) { vrDia = 27.00; regraAplicada = 'DETRAN - Moto Boy'; }
  else { vrDia = 588.00 / 30; regraAplicada = `DETRAN - Outras Funcoes (${funcao})`; }
  vtDia = 10.00;
} else if (contrato === 'TRE PB') {
  vrDia = 660.00 / 30;
  vtDia = 10.40;
  regraAplicada = 'TRE PB';
} else {
  vrDia = 24.50;
  vtDia = 10.00;
  regraAplicada = `Padrao (${contrato})`;
}
if (!optanteVT) vtDia = 0;
if (vtSoVolta && vtDia > 0) { vtDia = vtDia / 2; regraAplicada += ' + VT so volta (1/2)'; }
vrDia = round2(vrDia);
vtDia = round2(vtDia);

let descontoVR = 0;
let descontoVT = 0;
for (const d of hist.descontos_por_dia || []) {
  if (d.vt) descontoVT += vtDia;
  if (d.vr) {
    if (d.vr_tipo === 'atraso' && d.minutos_atraso) descontoVR += d.minutos_atraso >= 180 ? vrDia : vrDia * (d.minutos_atraso / 480);
    else descontoVR += vrDia;
  }
}
if (!optanteVT) descontoVT = 0;
descontoVR = round2(descontoVR);
descontoVT = round2(descontoVT);

let descontosRaw = [];
try { descontosRaw = $('Bloquear Desconto Consumido').first().json.descontos_existentes || []; }
catch (e) { descontosRaw = $input.all().map(i => i.json); }

const descontosList = [];
for (const j of descontosRaw) {
  if (!j || !j.id || !j.column_values) continue;
  const cols = {};
  for (const c of j.column_values) cols[c.id] = { text: c.text, value: c.value };
  const di = cols[COL_D_DATA_INICIO]?.text || null;
  const df = cols[COL_D_DATA_FIM]?.text || null;
  if (di === hist.data_inicio && df === hist.data_fim) {
    descontosList.push({ id: String(j.id), status: nomeNorm(cols[COL_D_STATUS]?.text), descontadoVR: num(cols[COL_D_DESCONTADO_VR]?.text), descontadoVT: num(cols[COL_D_DESCONTADO_VT]?.text) });
  }
}
const existente = descontosList[0] || null;
if (existente && (existente.status === 'PARCIAL' || existente.status === 'FINALIZADO' || existente.descontadoVR > 0 || existente.descontadoVT > 0)) {
  return [{ json: { _statusCode: 409, _erro: 'desconto_em_consumo', mensagem: 'Nao e possivel corrigir: o desconto desta convocacao ja foi parcial ou totalmente consumido.', acao: 'skip' } }];
}

function toDate(d) { return d ? { date: d } : null; }
function buildQuery(acao, existente, values) {
  const columnValuesJson = JSON.stringify(values);
  const columnValuesEscaped = JSON.stringify(columnValuesJson);
  if (acao === 'create') return { columnValuesJson, query: `mutation { create_item(board_id: ${BOARD_DESCONTOS}, group_id: "${GROUP_DESCONTOS}", item_name: "INTERMITENTE", column_values: ${columnValuesEscaped}, create_labels_if_missing: true) { id } }` };
  return { columnValuesJson, query: `mutation { change_multiple_column_values(board_id: ${BOARD_DESCONTOS}, item_id: ${existente.id}, column_values: ${columnValuesEscaped}, create_labels_if_missing: true) { id } }` };
}

if (descontoVR === 0 && descontoVT === 0) {
  if (!existente) return [{ json: { _statusCode: 200, acao: 'skip', motivo: 'sem_divida', regraAplicada, descontoVR, descontoVT, vrDia, vtDia } }];
  const values = { [COL_D_DIAS_PERDE_VT]: '0', [COL_D_DIAS_PERDE_VR]: '0', [COL_D_QTD_ATRASOS]: '0', [COL_D_DESCONTO_VR]: '0', [COL_D_DESCONTO_VT]: '0', [COL_D_STATUS]: { label: 'FINALIZADO' }, [COL_D_RESIDUAL_VR]: '0', [COL_D_RESIDUAL_VT]: '0', [COL_D_DESCONTADO_VR]: '0', [COL_D_DESCONTADO_VT]: '0' };
  const built = buildQuery('update', existente, values);
  return [{ json: { _statusCode: 200, acao: 'update', motivo: 'zerar_divida', item_id_desconto: existente.id, board_id: BOARD_DESCONTOS, column_values_json: built.columnValuesJson, query: built.query, descontoVR, descontoVT, regraAplicada, vrDia, vtDia } }];
}

const values = {
  [COL_D_NOME]: { labels: [hist.nome] },
  [COL_D_MATRICULA]: chapa,
  [COL_D_CPF]: cpf,
  [COL_D_DATA_INICIO]: toDate(hist.data_inicio),
  [COL_D_DATA_FIM]: toDate(hist.data_fim),
  [COL_D_DIAS_PERDE_VT]: String(hist.dias_perde_vt || 0),
  [COL_D_DIAS_PERDE_VR]: String(hist.dias_perde_vr || 0),
  [COL_D_QTD_ATRASOS]: String(hist.total_min_atraso || 0),
  [COL_D_DESCONTO_VR]: String(descontoVR),
  [COL_D_DESCONTO_VT]: String(descontoVT),
  [COL_D_STATUS]: { label: 'PENDENTE' },
  [COL_D_RESIDUAL_VR]: String(descontoVR),
  [COL_D_RESIDUAL_VT]: String(descontoVT),
  [COL_D_DESCONTADO_VR]: '0',
  [COL_D_DESCONTADO_VT]: '0'
};
for (const k of Object.keys(values)) if (values[k] === null || values[k] === undefined) delete values[k];
const acao = existente ? 'update' : 'create';
const built = buildQuery(acao, existente, values);
return [{ json: { _statusCode: 200, acao, item_id_desconto: existente?.id || null, board_id: BOARD_DESCONTOS, group_id: GROUP_DESCONTOS, item_name: 'INTERMITENTE', column_values_json: built.columnValuesJson, query: built.query, descontoVR, descontoVT, regraAplicada, vrDia, vtDia } }];

